SELECT community_id, name
FROM communities
WHERE risk_level = 'High';

SELECT COUNT(admission_id) AS number_of_admissions
FROM hospital_admissions
WHERE outbreak_id IS NULL;

SELECT SUM(reported_cases) AS total_reported_cases
FROM outbreak_updates
WHERE community = 0;

SELECT infected
FROM outbreak_updates
WHERE update_id = 0;

SELECT SUM(total_cases) AS total_covid_cases
FROM outbreaks
WHERE disease = 'COVID-19';

SELECT total_cases 
FROM outbreaks 
WHERE outbreak_id = 0;

SELECT update_id, infected
FROM outbreak_updates
WHERE infected > 50;

SELECT disease_type, SUM(total_cases) AS total_cases
FROM outbreaks
GROUP BY disease_type;

SELECT disease, total_cases
FROM outbreaks
ORDER BY total_cases DESC;
